export interface Todo {
  id: string;
  title: string;
  emoji: string;
  isCompleted: boolean;
  createdAt: number;
  completedAt: number | null;
}

export type CreateTodoInput = Pick<Todo, 'title' | 'emoji'>;

export type UpdateTodoInput = Partial<
  Pick<Todo, 'title' | 'emoji' | 'isCompleted' | 'completedAt'>
>;
