/**
 * 完了機能専用スタイル
 * DAデザイントークン・アニメーション仕様準拠
 */

/* ============================================================
   デザイントークン（カラー）
   ============================================================ */
:root {
  --color-completion-primary: #FF6B9D;
  --color-completion-secondary: #D8A5E8;
  --color-completion-success: #A8E6CF;
  --color-task-completed-text: #9B9B9B;
  --color-task-completed-bg: #FAFAFA;
  --color-task-incomplete-bg: #FFFFFF;
  --color-task-hover-bg: #FFDCC7;

  /* アニメーションタイミングトークン */
  --duration-check-appear: 150ms;
  --duration-checkbox-fill: 200ms;
  --duration-strikethrough: 250ms;
  --duration-strikethrough-delay: 100ms;
  --duration-card-fade: 300ms;
  --duration-sparkle: 400ms;
  --duration-list-reorder: 300ms;
  --easing-standard: ease-in-out;
  --easing-check: ease-out;
}

/* ============================================================
   TaskItem — ベーススタイル
   ============================================================ */
.task-item {
  display: flex;
  align-items: center;
  min-height: 64px;
  padding: 12px 16px;
  border-radius: 12px;
  margin-bottom: 8px;
  background: var(--color-task-incomplete-bg);
  border: 1px solid #F0F0F0;
  box-shadow: 0px 1px 4px rgba(0, 0, 0, 0.06);
  list-style: none;
  transition:
    background var(--duration-card-fade) var(--easing-standard),
    box-shadow var(--duration-card-fade) var(--easing-standard),
    opacity var(--duration-card-fade) var(--easing-standard);
}

.task-item:hover:not(.task-item--completed) {
  background: var(--color-task-hover-bg);
  box-shadow: 0px 2px 8px rgba(255, 107, 157, 0.15);
}

/* 完了済み状態 */
.task-item--completed {
  background: var(--color-task-completed-bg);
  box-shadow: none;
  opacity: 0.65;
}

/* ============================================================
   TaskItem — レイアウト
   ============================================================ */
.task-item__toggle-wrapper {
  flex-shrink: 0;
  position: relative;
}

.task-item__content {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
