  display: inline-block;
  word-break: break-word;
  transition: color var(--duration-card-fade) var(--easing-standard);
}

/* 取り消し線アニメーション（DAハンドオフノート: ::after疑似要素 + widthトランジション） */
.task-item__title::after {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  height: 2px;
  background: var(--color-completion-secondary); /* Lavender Purple #D8A5E8 */
  width: 0%;
  transition: width var(--duration-strikethrough) var(--easing-standard)
    var(--duration-strikethrough-delay);
  transform: translateY(-50%);
  border-radius: 1px;
}

/* 完了済み: 取り消し線100%展開 */
.task-item--completed .task-item__title {
  color: var(--color-task-completed-text);
}

.task-item--completed .task-item__title::after {
  width: 100%;
}

/* アクション */
.task-item__actions {
  flex-shrink: 0;
}

.task-item__delete-button {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: none;
  background: transparent;
  cursor: pointer;
  border-radius: 8px;
  color: #C0C0C0;
