}

/* ============================================================
   CompletionToggle — カスタムチェックボックス
   ============================================================ */
.completion-toggle {
  width: 44px;
  height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  border: none;
  background: transparent;
  padding: 0;
  flex-shrink: 0;
}

.completion-toggle:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

.completion-toggle__circle {
  width: 24px;
  height: 24px;
  border-radius: 50%;
  border: 2px solid var(--color-completion-secondary); /* Lavender Purple */
  background: transparent;
  transition:
    background var(--duration-checkbox-fill) var(--easing-standard),
    border-color var(--duration-checkbox-fill) var(--easing-standard);
  display: flex;
  align-items: center;
  justify-content: center;
}

.completion-toggle:hover .completion-toggle__circle {
  border-color: var(--color-completion-primary);
  background: rgba(255, 107, 157, 0.08);
}

.completion-toggle__circle--checked {
  background: var(--color-completion-primary);
  border-color: var(--color-completion-primary);
}

/* チェックマークSVGのストロークアニメーション */
.completion-toggle__checkmark {
  display: block;
}

.completion-toggle__checkmark path {
  stroke-dasharray: 20;
  stroke-dashoffset: 20;
  animation: draw-check var(--duration-check-appear) var(--easing-check) forwards;
}

@keyframes draw-check {
  to {
    stroke-dashoffset: 0;
  }
}

/* ============================================================
   TaskList — レイアウト
   ============================================================ */
.task-list {
  display: flex;
  flex-direction: column;
}

.task-list__section {
  list-style: none;
  padding: 0;
  margin: 0;
}

.task-list__completed-section {
  margin-top: 16px;
}

/* セクションラベル（DA仕様: 12px, Medium Gray, uppercase） */
.task-list__section-label {
  font-family: 'Inter', sans-serif;
  font-size: 12px;
  font-weight: 500;
  color: #9B9B9B;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin: 0 0 8px 0;
}

/* 全完了メッセージ */
.task-list__all-completed {
  animation: fade-in 200ms ease-out;
  margin-bottom: 16px;
}

.task-list__all-completed-text {
  font-family: 'Quicksand', sans-serif;
  font-size: 16px;
  font-weight: 600;
  color: var(--color-completion-primary);
  text-align: center;
  margin: 0;
}

/* 空状態 */
.task-list__empty {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px 16px;
}

.task-list__empty-text {
  font-family: 'Inter', sans-serif;
  font-size: 14px;
  color: #9B9B9B;
  text-align: center;
  margin: 0;
}

/* ============================================================
   スパークルパーティクル
   ============================================================ */
.sparkle-particle {
  position: fixed;
  border-radius: 50%;
  pointer-events: none;
  animation: sparkle-fly var(--duration-sparkle) ease-out forwards;
}

@keyframes sparkle-fly {
  0% {
    transform: translate(-50%, -50%) scale(1);
    opacity: 1;
  }
  60% {
    opacity: 0.8;
  }
  100% {
    transform: translate(
        calc(-50% + cos(var(--sparkle-angle, 45deg)) * var(--sparkle-distance, 30px)),
        calc(-50% + sin(var(--sparkle-angle, 45deg)) * var(--sparkle-distance, 30px))
      )
      scale(0);
    opacity: 0;
  }
}

/* ============================================================
   汎用アニメーション
   ============================================================ */
@keyframes fade-in {
  from {
    opacity: 0;
    transform: translateY(-4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
